class Solution:
    def maximumSum(self, nums, m, l, r):
        n = len(nums)
        S = [0] * (n + 1)
        for i in range(n):
            S[i + 1] = S[i] + nums[i]
        NEG = float('-inf')
        maxj = min(m, n // l)
        dp = [[NEG] * (maxj + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            for j in range(0, maxj + 1):
                best = dp[i - 1][j]
                if j >= 1:
                    for length in range(l, r + 1):
                        if i - length >= 0 and dp[i - length][j - 1] != NEG:
                            cand = dp[i - length][j - 1] + (S[i] - S[i - length])
                            if cand > best:
                                best = cand
                dp[i][j] = best
        best = NEG
        for j in range(1, maxj + 1):
            if dp[n][j] > best:
                best = dp[n][j]
        return best

