from collections import deque
class Solution:
    def maximumSum(self, nums, m: int, l: int, r: int) -> int:
        n = len(nums)
        S = [0] * (n + 1)
        for i in range(n):
            S[i + 1] = S[i] + nums[i]

        def solve(lam):
            dpVal = [0] * (n + 1)
            dpCnt = [0] * (n + 1)
            dq = deque()

            def key(k):
                return (dpVal[k] - S[k], -dpCnt[k])

            def push(k):
                kv = key(k)
                while dq and key(dq[-1]) <= kv:
                    dq.pop()
                dq.append(k)
            nextPush = 0
            for i in range(1, n + 1):
                lo = i - r
                hi = i - l
                while nextPush <= hi and nextPush <= n:
                    push(nextPush)
                    nextPush += 1
                while dq and dq[0] < lo:
                    dq.popleft()
                best = dpVal[i - 1]
                bestCnt = dpCnt[i - 1]
                if hi >= 0 and dq:
                    k = dq[0]
                    candVal = dpVal[k] - S[k] + S[i] - lam
                    candCnt = dpCnt[k] + 1
                    if candVal > best or (candVal == best and candCnt < bestCnt):
                        best = candVal
                        bestCnt = candCnt
                dpVal[i] = best
                dpCnt[i] = bestCnt
            return dpVal[n], dpCnt[n]

        def best_single_window():
            best = None
            for i in range(n + 1):
                for length in range(l, r + 1):
                    if i - length >= 0:
                        v = S[i] - S[i - length]
                        if best is None or v > best:
                            best = v
            return best

        maxAbs = max((abs(x) for x in nums), default=0)
        HI = r * maxAbs + 1
        lo, hi = 0, HI
        while lo < hi:
            mid = (lo + hi) // 2
            val, cnt = solve(mid)
            if cnt <= m:
                hi = mid
            else:
                lo = mid + 1
        lam = lo
        val, cnt = solve(lam)
        if cnt == 0:
            return best_single_window()
        return val + lam * m

