var maximumSum = function(nums, m, l, r) {
    const n = nums.length;
    const S = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) S[i + 1] = S[i] + nums[i];

    function solve(lam) {
        const dpVal = new Array(n + 1).fill(0);
        const dpCnt = new Array(n + 1).fill(0);
        const dq = [];
        let head = 0;
        function key(k) { return [dpVal[k] - S[k], -dpCnt[k]]; }
        function leq(a, b) { return a[0] !== b[0] ? a[0] <= b[0] : a[1] <= b[1]; }
        function push(k) {
            const kv = key(k);
            while (dq.length > head && leq(key(dq[dq.length - 1]), kv)) dq.pop();
            dq.push(k);
        }
        let nextPush = 0;
        for (let i = 1; i <= n; i++) {
            const lo = i - r;
            const hi = i - l;
            while (nextPush <= hi && nextPush <= n) { push(nextPush); nextPush++; }
            while (head < dq.length && dq[head] < lo) head++;
            let best = dpVal[i - 1];
            let bestCnt = dpCnt[i - 1];
            if (hi >= 0 && head < dq.length) {
                const k = dq[head];
                const candVal = dpVal[k] - S[k] + S[i] - lam;
                const candCnt = dpCnt[k] + 1;
                if (candVal > best || (candVal === best && candCnt < bestCnt)) {
                    best = candVal;
                    bestCnt = candCnt;
                }
            }
            dpVal[i] = best;
            dpCnt[i] = bestCnt;
        }
        return [dpVal[n], dpCnt[n]];
    }

    function bestSingleWindow() {
        let best = null;
        for (let i = 0; i <= n; i++) {
            for (let length = l; length <= r; length++) {
                if (i - length >= 0) {
                    const v = S[i] - S[i - length];
                    if (best === null || v > best) best = v;
                }
            }
        }
        return best;
    }

    let maxAbs = 0;
    for (const x of nums) maxAbs = Math.max(maxAbs, Math.abs(x));
    const HI = r * maxAbs + 1;
    let lo = 0, hi = HI;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        const [val, cnt] = solve(mid);
        if (cnt <= m) hi = mid; else lo = mid + 1;
    }
    const lam = lo;
    const [val, cnt] = solve(lam);
    if (cnt === 0) return bestSingleWindow();
    return val + lam * m;
};
